  // Debug endpoint: Get full call trace for debugging
  app.get('/api/debug/call-trace/:callSid', isAuthenticatedCustom, isAdmin, async (req: any, res) => {
    try {
      const { callSid } = req.params;
      console.log('[Debug][DEBUG] Fetching call trace for:', callSid);
      
      // Get session by callSid
      const session = await storage.getCallSessionByCallSid(callSid);
      
      // Get call events
      let events: any[] = [];
      if (session?.conversationId) {
        events = await storage.getCallEvents(session.conversationId);
      }
      
      // Try to find campaign target using conversationId
      let campaignTarget = null;
      const tenantId = (req.user as any).tenantId;
      if (session?.conversationId) {
        const targets = await storage.getCallTargetsBySession(session.conversationId, tenantId);
        if (targets.length > 0) {
          campaignTarget = targets[0];
        }
      }
      
      // Get Fly.io proxy status
      let flyioStatus = null;
      try {
        const flyResponse = await fetch('https://hemp-voice-proxy.fly.dev/sessions', {
          headers: { 'Authorization': `Bearer ${process.env.FLY_PROXY_SECRET || 'hemp-voice-proxy-secret-2024'}` }
        });
        if (flyResponse.ok) {
          flyioStatus = await flyResponse.json();
        }
      } catch (e) {
        flyioStatus = { error: 'Failed to fetch Fly.io status' };
      }
      
      res.json({
        callSid,
        session: session || null,
        events,
        campaignTarget,
        flyioProxySessions: flyioStatus,
        timestamp: new Date().toISOString(),
      });
    } catch (error: any) {
      console.error('[Debug][DEBUG] Error fetching call trace:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Get call queue status
  app.get('/api/elevenlabs/call-queue', isAuthenticatedCustom, async (req: any, res) => {
    try {
      const userId = req.user.isPasswordAuth ? req.user.id : req.user.claims.sub;
      const user = await storage.getUser(userId);
      
      // Check voice access
      const isAdminUser = await checkAdminAccess(user, req.user.tenantId);
      if (!isAdminUser && !user?.hasVoiceAccess) {
        return res.status(403).json({ error: 'Voice calling access required' });
      }

      // Get all active campaigns (scheduled or in-progress)
      const tenantId = (req.user as any).tenantId;
      const scheduledCampaigns = await storage.getCallCampaigns(tenantId, {
        status: 'scheduled',
        createdByUserId: (user?.roleInTenant === 'org_admin' || user?.role === 'admin') ? undefined : userId,
      });
      const inProgressCampaigns = await storage.getCallCampaigns(tenantId, {
        status: 'in-progress',
        createdByUserId: (user?.roleInTenant === 'org_admin' || user?.role === 'admin') ? undefined : userId,
      });
      const campaigns = [...scheduledCampaigns, ...inProgressCampaigns];

      // Get queue statistics
      const queueStats = {
        activeCalls: 0,
        queuedCalls: 0,
        completedToday: 0,
        failedToday: 0,
        campaigns: [] as any[],
      };

      for (const campaign of campaigns) {
        const targets = await storage.getCallCampaignTargets(campaign.id, tenantId);
        const pending = targets.filter((t: any) => t.targetStatus === 'pending').length;
        const completed = targets.filter((t: any) => t.targetStatus === 'completed').length;
        const failed = targets.filter((t: any) => t.targetStatus === 'failed').length;
        const inProgress = targets.filter((t: any) => t.targetStatus === 'in-progress').length;

        queueStats.queuedCalls += pending;
        queueStats.activeCalls += inProgress;
        queueStats.completedToday += completed;
        queueStats.failedToday += failed;

        queueStats.campaigns.push({
          ...campaign,
          pending,
          completed,
          failed,
          inProgress,
        });
      }

      res.json(queueStats);
    } catch (error: any) {
      console.error('Error fetching call queue:', error);
      res.status(500).json({ error: error.message || 'Internal server error' });
    }
  });

  // Get AI call analytics - completed calls with transcripts and metrics
  app.get('/api/elevenlabs/call-analytics', isAuthenticatedCustom, async (req: any, res) => {
    try {
      const userId = req.user.isPasswordAuth ? req.user.id : req.user.claims.sub;
      const user = await storage.getUser(userId);
      
      // Check voice access
      const isAdminUser = await checkAdminAccess(user, req.user.tenantId);
      if (!isAdminUser && !user?.hasVoiceAccess) {
        return res.status(403).json({ error: 'Voice calling access required' });
      }

      // Parse query filters
      const { agentId, startDate, endDate, outcome, projectId, limit = 50 } = req.query;
      const tenantId = req.user.tenantId;

      // Translate local agent UUID to ElevenLabs agent_id if provided
      let elevenLabsAgentId: string | undefined;
      if (agentId) {
        const localAgent = await storage.getElevenLabsAgent(agentId as string, tenantId);
        if (localAgent) {
          elevenLabsAgentId = localAgent.agentId;
        }
      }

      // Build SQL query for completed calls with transcripts
      let query = db
        .select({
          session: sql`json_build_object(
            'id', ${callSessions.id},
            'conversationId', ${callSessions.conversationId},
            'agentId', ${callSessions.agentId},
            'clientId', ${callSessions.clientId},
            'phoneNumber', ${callSessions.phoneNumber},
            'status', ${callSessions.status},
            'callDurationSecs', ${callSessions.callDurationSecs},
            'costCredits', ${callSessions.costCredits},
            'startedAt', ${callSessions.startedAt},
            'endedAt', ${callSessions.endedAt},
            'aiAnalysis', CASE 
              WHEN ${callSessions.aiAnalysis} IS NOT NULL 
              THEN ${callSessions.aiAnalysis}::jsonb 
              ELSE NULL 
            END,
            'callSuccessful', ${callSessions.callSuccessful},
            'interestLevel', ${callSessions.interestLevel},
            'followUpNeeded', ${callSessions.followUpNeeded},
            'followUpDate', ${callSessions.followUpDate},
            'nextAction', ${callSessions.nextAction},
            'storeSnapshot', ${callSessions.storeSnapshot}
          )`,
          client: sql`json_build_object(
            'id', ${clients.id},
            'uniqueIdentifier', ${clients.uniqueIdentifier},
            'data', ${clients.data}
          )`,
          transcriptCount: sql<number>`(
            SELECT COUNT(*)::int
            FROM call_transcripts
            WHERE conversation_id = ${callSessions.conversationId}
          )`,
        })
        .from(callSessions)
        .leftJoin(clients, eq(clients.id, callSessions.clientId))
        .where(sql`${callSessions.status} IN ('completed', 'failed') AND ${callSessions.tenantId} = ${tenantId}`);

      // Apply filters - use translated ElevenLabs agent_id
      if (elevenLabsAgentId) {
        query = query.where(eq(callSessions.agentId, elevenLabsAgentId));
      }
      if (startDate) {
        query = query.where(sql`${callSessions.startedAt} >= ${new Date(startDate as string)}`);
      }
      if (endDate) {
        query = query.where(sql`${callSessions.endedAt} <= ${new Date(endDate as string)}`);
      }
      if (outcome === 'successful') {
        query = query.where(eq(callSessions.callSuccessful, true));
      } else if (outcome === 'failed') {
        query = query.where(sql`${callSessions.callSuccessful} = false OR ${callSessions.status} = 'failed'`);
      }
      
      // Project filtering: filter calls by client's category matching project categories
      if (projectId) {
        const projectCategories = await db
          .select({ name: categories.name })
          .from(categories)
          .where(and(
            eq(categories.tenantId, tenantId),
            or(eq(categories.projectId, projectId as string), isNull(categories.projectId))
          ));
        const categoryNames = projectCategories.map(c => c.name.toLowerCase());
        
        if (categoryNames.length > 0) {
          // Include calls where client category matches project categories OR client has no category assigned
          query = query.where(
            or(
              inArray(sql`LOWER(${clients.category})`, categoryNames),
              isNull(clients.category),
              eq(clients.category, '')
            )
          );
        } else {
          // No categories for project = no calls should match
          query = query.where(sql`1 = 0`);
        }
      }

      // Order by most recent first and apply limit
      const calls = await query
        .orderBy(sql`${callSessions.startedAt} DESC`)
        .limit(parseInt(limit as string));

      // Calculate metrics
      const metrics = {
        totalCalls: calls.length,
        successfulCalls: calls.filter((c: any) => c.session.callSuccessful === true).length,
        failedCalls: calls.filter((c: any) => c.session.callSuccessful === false || c.session.status === 'failed').length,
        avgDurationSecs: Math.round(
          calls.reduce((sum: number, c: any) => sum + (c.session.callDurationSecs || 0), 0) / (calls.length || 1)
        ),
        interestLevels: {
          hot: calls.filter((c: any) => c.session.interestLevel === 'hot').length,
          warm: calls.filter((c: any) => c.session.interestLevel === 'warm').length,
          cold: calls.filter((c: any) => c.session.interestLevel === 'cold').length,
          notInterested: calls.filter((c: any) => c.session.interestLevel === 'not-interested').length,
        },
      };

      res.json({
        calls,
        metrics,
      });
    } catch (error: any) {
      console.error('Error fetching call analytics:', error);
      res.status(500).json({ error: error.message || 'Internal server error' });
    }
  });

  // Get full store row by link from Google Sheets
  app.get('/api/stores/by-link', isAuthenticatedCustom, async (req: any, res) => {
    try {
      const { link } = req.query;
      
      if (!link) {
        return res.status(400).json({ error: 'Link parameter is required' });
      }

      const tenantId = (req.user as any).tenantId;
      // Get sheets configuration
      const configuredSheets = await storage.getAllActiveGoogleSheets(tenantId);
      const storeSheet = configuredSheets.find((s: any) => s.sheetPurpose === "Store Database");
      
      if (!storeSheet) {
        return res.status(404).json({ error: 'Store Database sheet not configured' });
      }

      // Fetch all rows from Store Database
      const sheetData = await googleSheets.readSheetData(storeSheet.spreadsheetId, `${storeSheet.sheetName}!A:ZZ`);
      
      if (!sheetData || sheetData.length === 0) {
        return res.status(404).json({ error: 'No data found in Store Database' });
      }

      const headers = sheetData[0];
      const rows = sheetData.slice(1);

      // Find link column (case-insensitive)
      const linkColumnIndex = headers.findIndex((h: string) => 
        h.toLowerCase().trim() === 'link'
      );

      if (linkColumnIndex === -1) {
        return res.status(404).json({ error: 'Link column not found in Store Database' });
      }

      // Normalize the search link
      const normalizedSearchLink = normalizeLink(link as string);

      // Find matching row
      const matchingRowIndex = rows.findIndex((row: any[]) => {
        const rowLink = row[linkColumnIndex];
        if (!rowLink) return false;
        return normalizeLink(rowLink) === normalizedSearchLink;
      });

      if (matchingRowIndex === -1) {
        return res.status(404).json({ error: 'Store not found' });
      }

      // Convert row array to object with headers as keys
      const matchingRow = rows[matchingRowIndex];
      const storeRow: any = {};
      headers.forEach((header: string, index: number) => {
        storeRow[header] = matchingRow[index] || '';
      });

      // Add metadata needed by StoreDetailsDialog for saving edits
      // Row index is 2-based (header row + 1-indexed data rows)
      const rowIndex = matchingRowIndex + 2;

      res.json({ 
        storeRow,
        meta: {
          rowIndex,
          storeSheetId: storeSheet.id,
        }
      });
    } catch (error: any) {
      console.error('Error fetching store by link:', error);
      res.status(500).json({ error: error.message || 'Internal server error' });
    }
  });

  // Delete a call from both ElevenLabs and local database
  // Supports ?force=true query param to delete locally even when ElevenLabs fails
  app.delete('/api/elevenlabs/calls/:id', isAuthenticatedCustom, async (req: any, res) => {
    try {
      const { id } = req.params;
      const forceDelete = req.query.force === 'true';
      const userId = req.user.isPasswordAuth ? req.user.id : req.user.claims.sub;
      const user = await storage.getUser(userId);
      
      // Check voice access
      const isAdminUser = await checkAdminAccess(user, req.user.tenantId);
      if (!isAdminUser && !user?.hasVoiceAccess) {
        return res.status(403).json({ error: 'Voice calling access required' });
      }

      // Get the call session to find conversation ID
      const session = await db
        .select()
        .from(callSessions)
        .where(eq(callSessions.id, id))
        .limit(1);

      if (session.length === 0) {
        return res.status(404).json({ error: 'Call session not found' });
      }

      const conversationId = session[0].conversationId;
      let elevenLabsDeleted = false;
      let elevenLabsError: string | null = null;

      // Delete from ElevenLabs if conversation ID exists
      if (conversationId) {
        const elevenLabsConfig = await storage.getElevenLabsConfig(req.user.tenantId);
        if (!elevenLabsConfig?.apiKey) {
          if (!forceDelete) {
            // API key missing - abort to prevent orphaned conversations (unless forced)
            return res.status(503).json({ 
              error: 'ElevenLabs API key not configured. Cannot delete remote conversation. Use force=true to delete locally anyway.',
            });
          }
          elevenLabsError = 'API key not configured';
        } else {
          try {
            await axios.delete(
              `https://api.elevenlabs.io/v1/convai/conversations/${conversationId}`,
              {
                headers: {
                  'xi-api-key': elevenLabsConfig.apiKey,
                }
              }
            );
            console.log(`[DeleteCall] Deleted conversation ${conversationId} from ElevenLabs`);
            elevenLabsDeleted = true;
          } catch (err: any) {
            // If 404, conversation already gone - treat as success
            if (err.response?.status === 404) {
              console.log(`[DeleteCall] Conversation ${conversationId} not found in ElevenLabs (already deleted)`);
              elevenLabsDeleted = true;
            } else {
              elevenLabsError = err.response?.data?.error || err.message || 'Unknown ElevenLabs error';
              console.error('[DeleteCall] Failed to delete from ElevenLabs:', err.response?.data || err.message);
              
              if (!forceDelete) {
                // Other errors - abort the entire operation (unless forced)
                return res.status(500).json({ 
                  error: 'Failed to delete call from ElevenLabs. Local deletion aborted to prevent orphaned conversations. Use force=true to delete locally anyway.',
                  details: err.response?.data || err.message
                });
              }
            }
          }
        }
      }

      // Only delete from local database if ElevenLabs deletion succeeded (or no conversationId)
      // First delete related call_campaign_targets records (foreign key constraint)
      await db
        .delete(callCampaignTargets)
        .where(eq(callCampaignTargets.callSessionId, id));
      
      console.log(`[DeleteCall] Deleted call_campaign_targets for call session ${id}`);

      // Then delete the call session itself
      await db
        .delete(callSessions)
        .where(eq(callSessions.id, id));

      console.log(`[DeleteCall] Deleted call session ${id} from database`);

      // Build appropriate message based on deletion status
      let message = '';
      if (elevenLabsDeleted) {
        message = 'Call deleted successfully from both ElevenLabs and local database';
      } else if (elevenLabsError && forceDelete) {
        message = `Call deleted from local database (force mode). ElevenLabs deletion failed: ${elevenLabsError}`;
        console.log(`[DeleteCall] Force deleted call session ${id} locally despite ElevenLabs error: ${elevenLabsError}`);
      } else {
        message = 'Call deleted successfully from local database (no remote conversation)';
      }

      res.json({ 
        success: true, 
        message,
        deletedFromElevenLabs: elevenLabsDeleted,
        forcedDeletion: forceDelete && !!elevenLabsError,
        elevenLabsError: elevenLabsError || undefined,
      });
    } catch (error: any) {
      console.error('[DeleteCall] Error:', error);
      res.status(500).json({ error: error.message || 'Failed to delete call' });
    }
  });

