  // Configure multer for Aligner file uploads
  const alignerUpload = multer({
    storage: multer.memoryStorage(),
    limits: {
      fileSize: 50 * 1024 * 1024, // 50MB max
    },
    fileFilter: (req, file, cb) => {
      // Allowed file extensions
      const allowedExtensions = ['.txt', '.md', '.pdf', '.docx', '.csv'];
      const ext = file.originalname.toLowerCase().substring(file.originalname.lastIndexOf('.'));
      
      if (allowedExtensions.includes(ext)) {
        cb(null, true);
      } else {
        cb(new Error(`File type not allowed. Supported formats: ${allowedExtensions.join(', ')}`));
      }
    },
  });

  // Upload file to Aligner (multipart/form-data)
  app.post('/api/aligner/files', isAuthenticatedCustom, isAdmin, alignerUpload.single('file'), async (req: any, res) => {
    try {
      const file = req.file as Express.Multer.File;
      const { category } = req.body;
      const userId = req.user.isPasswordAuth ? req.user.id : req.user.claims.sub;
      const tenantId = await getEffectiveTenantId(req);
      
      if (!file) {
        return res.status(400).json({ error: 'File is required' });
      }
      
      const assistant = await storage.getAssistantBySlug('aligner', tenantId);
      if (!assistant) {
        return res.status(404).json({ error: 'Aligner assistant not found for this organization' });
      }

      // Get OpenAI settings
      const openaiSettings = await storage.getOpenaiSettings(tenantId);
      if (!openaiSettings?.apiKey) {
        return res.status(400).json({ error: 'OpenAI API key not configured' });
      }

      const openai = new OpenAI({ apiKey: openaiSettings.apiKey });

      // Create temporary file with binary content
      const fs = await import('fs/promises');
      const path = await import('path');
      const os = await import('os');
      
      const tmpDir = os.tmpdir();
      // Sanitize filename to prevent path traversal attacks
      const safeFilename = path.basename(file.originalname);
      const tmpFilePath = path.join(tmpDir, `aligner-upload-${Date.now()}-${safeFilename}`);
      
      // Write file buffer as binary (not UTF-8 text)
      await fs.writeFile(tmpFilePath, file.buffer);
      console.log(`[Aligner Upload] Temp file created: ${tmpFilePath} (${file.size} bytes)`);

      // Upload to OpenAI with original filename so OpenAI can detect file type
      const fileStream = await fs.open(tmpFilePath, 'r');
      const uploadedFile = await openai.files.create({
        file: await toFile(fileStream.createReadStream(), file.originalname),
        purpose: 'assistants',
      });
      
      await fileStream.close();
      
      // Clean up temp file
      await fs.unlink(tmpFilePath);
      console.log(`[Aligner Upload] ✅ File uploaded to OpenAI: ${uploadedFile.id}`);

      // If assistant has a vector store, add file to it with comprehensive error handling
      if (assistant.vectorStoreId) {
        console.log(`[Aligner Upload] Adding file to vector store: ${assistant.vectorStoreId}`);
        try {
          const vectorStoreFile = await openai.vectorStores.files.create(assistant.vectorStoreId, {
            file_id: uploadedFile.id,
          });
          console.log(`[Aligner Upload] ✅ File added to vector store. Status: ${vectorStoreFile.status}`);
          
          // Poll file status to check for processing errors
          console.log(`[Aligner Upload] Polling file status to verify processing...`);
          let maxAttempts = 30; // 30 seconds max
          let attempt = 0;
          let finalStatus = vectorStoreFile.status;
          
          while (attempt < maxAttempts) {
            try {
              const fileStatus = await openai.vectorStores.files.retrieve(
                uploadedFile.id,
                { vector_store_id: assistant.vectorStoreId }
              );
              
              finalStatus = fileStatus.status;
              console.log(`[Aligner Upload] File status: ${fileStatus.status} (attempt ${attempt + 1}/${maxAttempts})`);
              
              if (fileStatus.status === 'completed') {
                console.log(`[Aligner Upload] ✅ File processing completed successfully`);
                break;
              } else if (fileStatus.status === 'failed') {
                console.error(`[Aligner Upload] ❌ File processing FAILED`);
                console.error(`[Aligner Upload] Error code: ${fileStatus.last_error?.code || 'unknown'}`);
                console.error(`[Aligner Upload] Error message: ${fileStatus.last_error?.message || 'No error message provided'}`);
                console.error(`[Aligner Upload] Full error object:`, JSON.stringify(fileStatus.last_error, null, 2));
                throw new Error(`OpenAI failed to process file: ${fileStatus.last_error?.message || 'Unknown error'}`);
              } else if (fileStatus.status === 'cancelled') {
                console.error(`[Aligner Upload] ⚠️ File processing was cancelled`);
                throw new Error('File processing was cancelled');
              }
              
              // Still processing, wait before next poll
              await new Promise(resolve => setTimeout(resolve, 1000));
              attempt++;
            } catch (pollError: any) {
              // If it's our thrown error, re-throw it
              if (pollError.message.includes('OpenAI failed to process file') || pollError.message.includes('cancelled')) {
                throw pollError;
              }
              // Otherwise it's a retrieval error
              console.error(`[Aligner Upload] Error polling file status (attempt ${attempt + 1}):`, pollError.message);
              attempt++;
              await new Promise(resolve => setTimeout(resolve, 1000));
            }
          }
          
          if (attempt >= maxAttempts && finalStatus === 'in_progress') {
            console.warn(`[Aligner Upload] ⚠️ File still processing after ${maxAttempts} seconds. Status: ${finalStatus}`);
          }
          
          // Verify by reading back the file list from OpenAI
          console.log(`[Aligner Upload] Verifying file in vector store...`);
          try {
            const filesInStore = await openai.vectorStores.files.list(assistant.vectorStoreId, { limit: 10 });
            const ourFile = filesInStore.data.find(f => f.id === uploadedFile.id);
            if (ourFile) {
              console.log(`[Aligner Upload] ✅ VERIFIED: File found in vector store with status: ${ourFile.status}`);
            } else {
              console.log(`[Aligner Upload] ⚠️ WARNING: File not found in vector store list`);
            }
            console.log(`[Aligner Upload] Total files in vector store: ${filesInStore.data.length}`);
          } catch (verifyError: any) {
            console.error(`[Aligner Upload] ⚠️ Could not verify file in vector store:`, verifyError.message);
          }
        } catch (vectorError: any) {
          console.error(`[Aligner Upload] ❌ FAILED to add file to vector store:`, vectorError.message);
          console.error(`[Aligner Upload] Error details:`, vectorError);
          throw new Error(`Vector store attachment failed: ${vectorError.message}`);
        }
      } else {
        console.log(`[Aligner Upload] ⚠️ No vector store configured for assistant`);
      }

      // Create database record
      const dbFile = await storage.createAssistantFile({
        tenantId,
        assistantId: assistant.id,
        filename: file.originalname,
        openaiFileId: uploadedFile.id,
        fileSize: file.size,
        uploadedBy: userId,
        category: category || 'general',
      });

      console.log(`[Aligner Upload] ✅ File uploaded successfully: ${file.originalname}`);
      res.json({ file: dbFile });
    } catch (error: any) {
      console.error('[Aligner] Error uploading file:', error);
      res.status(500).json({ error: error.message || 'Failed to upload file' });
    }
  });

  // Delete Aligner file
  app.delete('/api/aligner/files/:fileId', isAuthenticatedCustom, isAdmin, async (req: any, res) => {
    try {
      const { fileId } = req.params;
      const tenantId = await getEffectiveTenantId(req);
      
      // Get the file info first to get the OpenAI file ID
      const fileInfo = await storage.getAssistantFileById(fileId);
      if (!fileInfo) {
        return res.status(404).json({ error: 'File not found' });
      }
      
      // Get Aligner assistant
      const alignerAssistant = await storage.getAssistantBySlug('aligner', tenantId);
      if (!alignerAssistant) {
        return res.status(404).json({ error: 'Aligner assistant not found for this organization' });
      }
      
      // Verify the file belongs to this assistant
      if (fileInfo.assistantId !== alignerAssistant.id) {
        return res.status(404).json({ error: 'File not found or does not belong to Aligner assistant' });
      }

      // Delete from OpenAI if we have the OpenAI file ID and vector store
      if (fileInfo.openaiFileId && alignerAssistant.vectorStoreId) {
        try {
          const openaiSettings = await storage.getOpenaiSettings(tenantId);
          if (openaiSettings?.apiKey) {
            const openai = new OpenAI({ apiKey: openaiSettings.apiKey });
            
            // Remove file from vector store first (SDK v6: vectorStoreId, fileId)
            try {
              await openai.vectorStores.files.del(alignerAssistant.vectorStoreId, fileInfo.openaiFileId);
              console.log(`[Aligner Delete] Removed file ${fileInfo.openaiFileId} from vector store`);
            } catch (vsError: any) {
              // Log but continue - file might already be removed from vector store
              console.log(`[Aligner Delete] Could not remove from vector store (may already be removed): ${vsError.message}`);
            }
            
            // Delete the file from OpenAI (SDK v6: files.del not files.delete)
            try {
              await openai.files.del(fileInfo.openaiFileId);
              console.log(`[Aligner Delete] Deleted file ${fileInfo.openaiFileId} from OpenAI`);
            } catch (fileError: any) {
              // Log but continue - file might already be deleted
              console.log(`[Aligner Delete] Could not delete from OpenAI (may already be deleted): ${fileError.message}`);
            }
          }
        } catch (openaiError: any) {
          // Log but continue with local deletion
          console.error(`[Aligner Delete] OpenAI deletion error: ${openaiError.message}`);
        }
      }

      // Delete from local database
      const deleted = await storage.deleteAssistantFileByAssistantId(fileId, alignerAssistant.id);
      
      if (!deleted) {
        return res.status(404).json({ error: 'Failed to delete file from database' });
      }
      
      console.log(`[Aligner Delete] Successfully deleted file: ${fileInfo.filename}`);
      res.json({ success: true });
    } catch (error: any) {
      console.error('[Aligner] Error deleting file:', error);
      res.status(500).json({ error: error.message || 'Failed to delete file' });
    }
  });

  // Sync KB files to Aligner assistant's vector store on OpenAI
  app.post('/api/aligner/sync-kb', isAuthenticatedCustom, isAdmin, async (req: any, res) => {
    try {
      console.log('[Aligner Sync] Starting KB files sync to OpenAI vector store...');
      const tenantId = await getEffectiveTenantId(req);
      
      // Get Aligner assistant
      const alignerAssistant = await storage.getAssistantBySlug('aligner', tenantId);
      if (!alignerAssistant) {
        return res.status(404).json({ error: 'Aligner assistant not found for this organization' });
      }

      if (!alignerAssistant.assistantId) {
        return res.status(400).json({ error: 'Aligner assistant ID not configured. Please set the assistant ID first.' });
      }

      // Get OpenAI settings
      const openaiSettings = await storage.getOpenaiSettings(tenantId);
      if (!openaiSettings?.apiKey) {
        return res.status(400).json({ error: 'OpenAI API key not configured' });
      }

      const openai = new OpenAI({ apiKey: openaiSettings.apiKey });

      // Create vector store if doesn't exist
      let vectorStoreId = alignerAssistant.vectorStoreId;
      if (!vectorStoreId) {
        console.log('[Aligner Sync] Creating new vector store for Aligner...');
        const vectorStore = await openai.vectorStores.create({
          name: 'Aligner KB Files',
        });
        vectorStoreId = vectorStore.id;
        
        // Save to database
        await storage.updateAssistant(alignerAssistant.id, { vectorStoreId });
        
        // Update OpenAI assistant to use vector store
        await openai.beta.assistants.update(alignerAssistant.assistantId, {
          tools: [{ type: 'file_search' }],
          tool_resources: {
            file_search: {
              vector_store_ids: [vectorStoreId]
            }
          }
        });
        
        console.log('[Aligner Sync] Vector store created and linked:', vectorStoreId);
      } else {
        console.log('[Aligner Sync] Using existing vector store:', vectorStoreId);
      }

      // Get all assistant files from database
      const dbFiles = await storage.getAssistantFiles(alignerAssistant.id);
      console.log(`[Aligner Sync] Found ${dbFiles.length} files in database`);

      // List files in OpenAI vector store
      let vectorStoreFiles: any[] = [];
      try {
        const response = await openai.vectorStores.files.list(vectorStoreId, { limit: 100 });
        vectorStoreFiles = response.data || [];
        console.log(`[Aligner Sync] Found ${vectorStoreFiles.length} files in OpenAI vector store`);
      } catch (error: any) {
        console.error('[Aligner Sync] Error listing vector store files:', error);
        // Continue even if listing fails
      }

      // Create a set of OpenAI file IDs in vector store
      const vectorStoreFileIds = new Set(vectorStoreFiles.map(f => f.id));

      // Check which database files are missing from vector store
      const missingFiles = dbFiles.filter(f => !vectorStoreFileIds.has(f.openaiFileId));
      console.log(`[Aligner Sync] Found ${missingFiles.length} files missing from vector store`);

      let resynced = 0;
      let failed = 0;
      const errors: string[] = [];

      // Re-upload missing files to vector store
      for (const file of missingFiles) {
        try {
          console.log(`[Aligner Sync] Re-adding file to vector store: ${file.filename}`);
          await openai.vectorStores.files.create(vectorStoreId, {
            file_id: file.openaiFileId,
          });
          resynced++;
        } catch (error: any) {
          console.error(`[Aligner Sync] Failed to re-add ${file.filename}:`, error);
          failed++;
          errors.push(`${file.filename}: ${error.message}`);
        }
      }

      const summary = {
        success: true,
        totalInDb: dbFiles.length,
        totalInVectorStore: vectorStoreFiles.length,
        resynced,
        failed,
        alreadySynced: dbFiles.length - missingFiles.length,
        errors: errors.length > 0 ? errors : undefined,
      };

      console.log('[Aligner Sync] Complete:', summary);
      res.json(summary);
    } catch (error: any) {
      console.error('[Aligner Sync] Error syncing KB files:', error);
      res.status(500).json({ error: error.message || 'Failed to sync KB files' });
    }
  });

