  app.post('/api/maps/save-to-sheet', isAuthenticatedCustom, async (req: any, res) => {
    try {
      const userId = req.user.isPasswordAuth ? req.user.id : req.user.claims.sub;
      const { placeId, category, projectId } = req.body;

      if (!placeId) {
        return res.status(400).json({ message: 'Place ID is required' });
      }

      // Get place details from Google Maps
      const placeDetails = await googleMaps.getPlaceDetails(placeId);

      if (!placeDetails) {
        return res.status(404).json({ message: 'Place not found' });
      }

      // Parse address into street, city, state, zip components for separate CRM columns
      const { street, city, state, zip, country } = googleMaps.extractAddressFromComponents(placeDetails.address_components, placeDetails.formatted_address);


      // Use project name as category if projectId is provided
      const tenantId = (req.user as any).tenantId;
      let effectiveCategory = category;
      if (projectId) {
        const project = await storage.getTenantProjectById(projectId, tenantId);
        if (project) {
          effectiveCategory = project.name;
        }
      }

      if (!effectiveCategory) {
        return res.status(400).json({ message: 'Category or valid projectId is required' });
      }

      // Auto-create category if it doesn't exist (frictionless category creation)
      if (effectiveCategory && effectiveCategory.trim() && tenantId) {
        await storage.getOrCreateCategoryByName(tenantId, effectiveCategory.trim(), projectId);
      }

      // Find Store Database sheet for this category
      const sheets = await storage.getAllActiveGoogleSheets((req.user as any).tenantId);
      const storeSheet = sheets.find(s => s.sheetPurpose === 'Store Database');

      if (!storeSheet) {
        return res.status(404).json({ message: 'Store Database sheet not found. Please connect a Google Sheet first.' });
      }

      // Format hours more concisely - just show if open and basic hours
      const formatHours = (weekdayText?: string[]): string => {
        if (!weekdayText || weekdayText.length === 0) return '';
        // Just take the first entry as a sample
        return weekdayText[0] || '';
      };

      // Read Store Database headers to get column positions (header-based writing)
      const storeRange = `${storeSheet.sheetName}!A:ZZ`;
      const storeRows = await googleSheets.readSheetData(storeSheet.spreadsheetId, storeRange);
      
      if (!storeRows || storeRows.length === 0) {
        return res.status(500).json({ message: 'Store Database sheet is empty or has no headers' });
      }

      // CRITICAL: Filter out empty headers to prevent sheet pollution
      const allHeaders = storeRows[0];
      const headers = allHeaders.filter(h => h && h.trim() !== '');
      
      // Find column indices by header name (case-insensitive)
      const findColumnIndex = (columnName: string) => 
        headers.findIndex((h: string) => h.toLowerCase() === columnName.toLowerCase());

      const nameIndex = findColumnIndex('name');
      const typeIndex = findColumnIndex('type');
      const linkIndex = findColumnIndex('link');
      const memberSinceIndex = findColumnIndex('member since');
      const addressIndex = findColumnIndex('address');
      const cityIndex = findColumnIndex('city');
      const stateIndex = findColumnIndex('state');
      const zipIndex = findColumnIndex('zip');
      const phoneIndex = findColumnIndex('phone');
      const websiteIndex = findColumnIndex('website');
      const emailIndex = findColumnIndex('email');
      const followersIndex = findColumnIndex('followers');
      const tagsIndex = findColumnIndex('tags');
      const hoursIndex = findColumnIndex('hours');
      const dbaIndex = findColumnIndex('dba');
      const vibeScoreIndex = findColumnIndex('vibe score');
      const salesReadyIndex = findColumnIndex('sales-ready summary');
      const agentNameIndex = findColumnIndex('agent name');
      const openIndex = findColumnIndex('open');
      const categoryIndex = findColumnIndex('category');
      const countryIndex = findColumnIndex('country');

      // Build row dynamically based on actual header positions
      const row = new Array(headers.length).fill('');
      
      if (nameIndex !== -1) row[nameIndex] = placeDetails.name || '';
      if (typeIndex !== -1) row[typeIndex] = placeDetails.types?.[0] || '';
      if (linkIndex !== -1) row[linkIndex] = placeDetails.url || `https://www.google.com/maps/place/?q=place_id:${placeDetails.place_id}`;
      if (addressIndex !== -1) row[addressIndex] = street;
      if (cityIndex !== -1) row[cityIndex] = city;
      if (stateIndex !== -1) row[stateIndex] = state;
      if (zipIndex !== -1) row[zipIndex] = zip;
      if (phoneIndex !== -1) row[phoneIndex] = placeDetails.formatted_phone_number || placeDetails.international_phone_number || '';
      if (websiteIndex !== -1) row[websiteIndex] = placeDetails.website || '';
      if (hoursIndex !== -1) row[hoursIndex] = formatHours(placeDetails.opening_hours?.weekday_text);
      if (openIndex !== -1) row[openIndex] = placeDetails.business_status === 'OPERATIONAL' ? 'TRUE' : 'FALSE';
      if (categoryIndex !== -1) row[categoryIndex] = effectiveCategory;
      if (countryIndex !== -1) row[countryIndex] = country;

      // Append to Google Sheet (header-based, works regardless of column order/additions)
      const range = `${storeSheet.sheetName}!A:ZZ`;
      await googleSheets.appendSheetData(storeSheet.spreadsheetId, range, [row]);

      // Record this place_id to prevent duplicates in future searches
      await storage.recordImportedPlace(placeId, req.user.tenantId);

      res.json({ 
        message: 'Place saved successfully to Store Database',
        place: {
          name: placeDetails.name,
          address: placeDetails.formatted_address,
          category: effectiveCategory
        }
      });
    } catch (error: any) {
      console.error('Error saving place to sheet:', error);
      res.status(500).json({ message: error.message || 'Failed to save place to sheet' });
    }
  });

  // Save place to Qualification Leads database table
  app.post('/api/maps/save-to-qualification', isAuthenticatedCustom, async (req: any, res) => {
    try {
      const tenantId = req.user.tenantId;
      const { placeId, category, projectId } = req.body;

      if (!placeId) {
        return res.status(400).json({ message: 'Place ID is required' });
      }

      if (!tenantId) {
        return res.status(400).json({ message: 'Tenant context required' });
      }

      // Get place details from Google Maps
      const placeDetails = await googleMaps.getPlaceDetails(placeId);

      if (!placeDetails) {
        return res.status(404).json({ message: 'Place not found' });
      }

      // Parse address into components
      const { street, city, state, zip, country: extractedCountry } = googleMaps.extractAddressFromComponents(placeDetails.address_components, placeDetails.formatted_address);

      const country = extractedCountry || 'United States';
      
      // Extract country code for timezone lookup
      let countryCode = 'US';
      if (placeDetails.address_components) {
        const countryComponent = placeDetails.address_components.find(
          (c: any) => c.types?.includes('country')
        );
        if (countryComponent) {
          countryCode = countryComponent.short_name || countryCode;
        }
      }

      // Use project name as category if projectId is provided
      let effectiveCategory = category;
      if (projectId) {
        const project = await storage.getTenantProjectById(projectId, tenantId);
        if (project) {
          effectiveCategory = project.name;
        }
      }

      if (!effectiveCategory) {
        return res.status(400).json({ message: 'Category or valid projectId is required' });
      }

      // Auto-create category if it doesn't exist (frictionless category creation)
      if (effectiveCategory && effectiveCategory.trim()) {
        await storage.getOrCreateCategoryByName(tenantId, effectiveCategory.trim(), projectId);
      }

      // Create qualification lead from place data
      const leadData = {
        tenantId,
        company: placeDetails.name || 'Unknown Business',
        website: placeDetails.website || null,
        category: effectiveCategory || null,
        projectId: projectId || null,
        pocPhone: placeDetails.formatted_phone_number || placeDetails.international_phone_number || null,
        address: street || null,
        city: city || null,
        state: state || null,
        postalCode: zip || null,
        country,
        countryCode,
        source: 'map_search',
        callStatus: 'pending',
        tags: placeDetails.types || [],
      };

      const createdLead = await storage.createQualificationLead(leadData);

      // Record this place_id to prevent duplicates in future searches
      await storage.recordImportedPlace(placeId, tenantId);

      res.json({ 
        message: 'Lead saved successfully to Qualification Leads',
        lead: {
          id: createdLead.id,
          company: createdLead.company,
          city: createdLead.city,
          state: createdLead.state,
          category: createdLead.category
        }
      });
    } catch (error: any) {
      console.error('Error saving place to qualification leads:', error);
      res.status(500).json({ message: error.message || 'Failed to save lead' });
    }
  });

  // Check for duplicate websites in CRM (Google Sheets or SQL based on tenant config)
  app.post("/api/maps/check-duplicates", isAuthenticatedCustom, async (req: any, res) => {
    try {
      const tenantId = req.user.tenantId;
      const { websites } = req.body as { websites: string[] };

      if (!tenantId) {
        return res.status(400).json({ message: "Tenant context required" });
      }

      if (!websites || !Array.isArray(websites) || websites.length === 0) {
        return res.json({ duplicates: [] });
      }

      // Normalize URLs for comparison (lowercase, trim, remove trailing slashes)
      const normalizeUrl = (url: string): string => {
        if (!url) return "";
        let normalized = url.toLowerCase().trim();
        // Remove protocol
        normalized = normalized.replace(/^https?:\/\//, "");
        // Remove www.
        normalized = normalized.replace(/^www\./, "");
        // Remove trailing slash
        normalized = normalized.replace(/\/$/, "");
        return normalized;
      };

      const normalizedInputUrls = new Map<string, string>();
      for (const url of websites) {
        const normalized = normalizeUrl(url);
        if (normalized) {
          normalizedInputUrls.set(normalized, url);
        }
      }

      const duplicates: string[] = [];

      // Check if tenant has a Store Database sheet
      const sheets = await storage.getAllActiveGoogleSheets(tenantId);
      const storeSheet = sheets.find(s => s.sheetPurpose === "Store Database");

      if (storeSheet) {
        // Check Google Sheets for duplicates
        const storeRange = `${storeSheet.sheetName}!A:ZZ`;
        const storeRows = await googleSheets.readSheetData(storeSheet.spreadsheetId, storeRange);

        if (storeRows && storeRows.length > 1) {
          const headers = storeRows[0].map((h: string) => (h || "").toLowerCase().trim());
          const websiteIndex = headers.indexOf("website");

          if (websiteIndex !== -1) {
            // Check each row's website against input URLs
            for (let i = 1; i < storeRows.length; i++) {
              const row = storeRows[i];
              const websiteValue = row[websiteIndex]?.toString() || "";
              const normalizedExisting = normalizeUrl(websiteValue);
              
              if (normalizedExisting && normalizedInputUrls.has(normalizedExisting)) {
                duplicates.push(normalizedInputUrls.get(normalizedExisting)!);
              }
            }
          }
        }
      } else {
        // Check SQL qualification_leads for duplicates
        const { leads } = await storage.listQualificationLeads(tenantId, { limit: 10000 });
        
        for (const lead of leads) {
          if (lead.website) {
            const normalizedExisting = normalizeUrl(lead.website);
            if (normalizedExisting && normalizedInputUrls.has(normalizedExisting)) {
              duplicates.push(normalizedInputUrls.get(normalizedExisting)!);
            }
          }
        }
      }

      // Return unique duplicates
      res.json({ duplicates: [...new Set(duplicates)] });
    } catch (error: any) {
      console.error("Error checking duplicates:", error);
      res.status(500).json({ message: error.message || "Failed to check duplicates" });
    }
  });

