  // Append message to strategy chat and get AI response (admin only)
  app.post('/api/sequences/:id/strategy-chat', isAuthenticatedCustom, isAdmin, async (req: any, res) => {
    try {
      const { id } = req.params;
      const userId = req.user?.id;
      
      // Validate message
      const { message } = z.object({
        message: z.string().min(1, 'Message is required'),
      }).parse(req.body);

      // Check sequence exists
      const sequence = await storage.getSequence(id, req.user.tenantId);
      if (!sequence) {
        return res.status(404).json({ message: 'Sequence not found' });
      }

      // Get Aligner assistant
      const alignerAssistant = await storage.getAssistantBySlug('aligner', req.user.tenantId);
      if (!alignerAssistant || !alignerAssistant.assistantId) {
        return res.status(400).json({ message: 'Aligner assistant not configured' });
      }

      // Get OpenAI settings
      const openaiSettings = await storage.getOpenaiSettings(req.user.tenantId);
      if (!openaiSettings || !openaiSettings.apiKey) {
        return res.status(400).json({ message: 'OpenAI API key not configured' });
      }

      // Get E-Hub settings for prompt injection and keyword bin
      const ehubSettings = await storage.getEhubSettings(req.user.tenantId);
      const promptInjection = ehubSettings?.promptInjection || '';
      const keywordBin = ehubSettings?.keywordBin || '';

      const openai = new OpenAI({ apiKey: openaiSettings.apiKey });

      // Get or create thread for this sequence
      const existingTranscript = sequence.strategyTranscript || { messages: [], lastUpdatedAt: new Date().toISOString() };
      let threadId = (existingTranscript as any).threadId;

      if (!threadId) {
        // Create new thread for persistent conversation
        const thread = await openai.beta.threads.create();
        threadId = thread.id;
        console.log('[E-Hub Strategy] New thread created:', threadId);
      }

      // Build contextual instructions with E-Hub settings
      const contextualInstructions = `## YOUR ROLE:
You are The Bellwether Outreach Architect, an AI strategist that designs short, high-signal outreach emails for cannabis industry professionals and brands.

Your job is to craft campaigns that grab attention, build credibility, and convert genuine curiosity into conversation — without ever sounding like advertising.

## E-HUB CAMPAIGN CONTEXT:
${promptInjection ? `**Campaign Tone & Structure:**\n${promptInjection}\n\n` : ''}${keywordBin ? `**Product/Business Keywords:**\n${keywordBin}\n\n` : ''}
## YOUR WORKFLOW:

When the user asks you to plan a campaign:

1. **UNDERSTAND THE GOAL** - Ask clarifying questions:
   - Campaign objectives (re-engagement, new customer acquisition, partnership, etc.)
   - Target audience characteristics
   - Key value propositions to highlight
   - Tone preference (professional, friendly, consultative, etc.)
   - Any specific constraints or requirements

2. **SUGGEST SEQUENCE STRUCTURE** - Recommend optimal multi-step flow:
   - Number of follow-up steps (typically 2-4)
   - Timing between emails (days)
   - Escalation strategy (soft → direct)

3. **HELP CRAFT MESSAGING** - Guide the user on:
   - Opening hooks that build trust
   - Personalization opportunities
   - Clear but soft calls-to-action
   - Follow-up angles that add value

Based on the conversation, help the user design an effective email sequence that achieves their goals.`;

      // Add contextual instructions + user message to thread
      const enrichedMessage = `${contextualInstructions}\n\nUser: ${message}`;
      
      await openai.beta.threads.messages.create(threadId, {
        role: 'user',
        content: enrichedMessage
      });

      // Run the Aligner assistant
      const run = await openai.beta.threads.runs.create(threadId, {
        assistant_id: alignerAssistant.assistantId,
      });

      // Poll for completion
      let runStatus = await openai.beta.threads.runs.retrieve(run.id, { thread_id: threadId });
      let attempts = 0;
      const maxAttempts = 60; // 60 seconds timeout

      while (runStatus.status === 'queued' || runStatus.status === 'in_progress') {
        await new Promise(resolve => setTimeout(resolve, 1000));
        runStatus = await openai.beta.threads.runs.retrieve(run.id, { thread_id: threadId });
        attempts++;
        
        if (attempts >= maxAttempts) {
          throw new Error('Strategy chat timeout - response took too long');
        }
      }

      if (runStatus.status !== 'completed') {
        throw new Error(`Strategy chat failed: ${runStatus.status}`);
      }

      // Get assistant's response
      const messages = await openai.beta.threads.messages.list(threadId, { limit: 1 });
      const lastMessage = messages.data[0];
      
      if (!lastMessage || lastMessage.role !== 'assistant') {
        throw new Error('No response from Aligner assistant');
      }

      const aiResponse = lastMessage.content
        .filter((block: any) => block.type === 'text')
        .map((block: any) => block.text.value)
        .join('\n\n') || 'Sorry, I could not generate a response.';

      // Save both messages to transcript and persist threadId
      const updatedSequence = await storage.appendSequenceStrategyMessages(
        id, 
        [
          { role: 'user', content: message, createdBy: userId },
          { role: 'assistant', content: aiResponse },
        ],
        threadId
      );

      res.json({
        transcript: updatedSequence.strategyTranscript,
        aiResponse,
      });
    } catch (error: any) {
      if (error.name === 'ZodError') {
        return res.status(400).json({ message: 'Invalid message data', errors: error.errors });
      }
      console.error('Error in strategy chat:', error);
      res.status(500).json({ message: error.message || 'Failed to process strategy chat' });
    }
  });

  // Generate finalized strategy brief from transcript (admin only)
  app.post('/api/sequences/:id/finalize-strategy', isAuthenticatedCustom, isAdmin, async (req: any, res) => {
    try {
      const { id } = req.params;
      
      // Check sequence exists and has strategy transcript
      const sequence = await storage.getSequence(id, req.user.tenantId);
      if (!sequence) {
        return res.status(404).json({ message: 'Sequence not found' });
      }
      
      if (!sequence.strategyTranscript || !sequence.strategyTranscript.messages || sequence.strategyTranscript.messages.length === 0) {
        return res.status(400).json({ message: 'No strategy messages to finalize. Start a conversation first.' });
      }
      
      // Get Aligner assistant for strategy synthesis
      const alignerAssistant = await storage.getAssistantBySlug('aligner', req.user.tenantId);
      if (!alignerAssistant || !alignerAssistant.assistantId) {
        return res.status(400).json({ message: 'Aligner assistant not configured' });
      }

      // Get OpenAI settings
      const openaiSettings = await storage.getOpenaiSettings(req.user.tenantId);
      if (!openaiSettings || !openaiSettings.apiKey) {
        return res.status(400).json({ message: 'OpenAI API key not configured' });
      }
      
      const openai = new OpenAI({ apiKey: openaiSettings.apiKey });
      
      // Build conversation context from transcript
      let conversationContext = 'Here is the complete strategy conversation:\n\n';
      sequence.strategyTranscript.messages.forEach(msg => {
        const role = msg.role === 'user' ? 'USER' : 'ASSISTANT';
        conversationContext += `${role}: ${msg.content}\n\n`;
      });
      
      // Build synthesis prompt for Aligner
      const synthesisPrompt = `You are a campaign strategy distillation expert. Your job is to read an entire strategy conversation and distill it into a concise, actionable campaign brief.

REQUIREMENTS:
- 200-300 words maximum
- Clear, directive tone (not conversational)
- Include: target audience, campaign goals, tone/voice, key messaging points, constraints
- Organize with clear sections using markdown headers
- This will be injected into email generation prompts, so be specific and actionable
- Do NOT include explanations or meta-commentary - just the pure strategic brief

Output format example:
## Target Audience
[Who we're reaching]

## Campaign Goals
[What we want to achieve]

## Tone & Voice
[How we should sound]

## Key Messaging
[Core points to emphasize]

## Constraints
[What to avoid or requirements]

${conversationContext}`;

      console.log('[E-Hub Finalize] 🤖 Using Aligner assistant to synthesize Campaign Brief');

      // Create thread and run with Aligner
      const thread = await openai.beta.threads.create({
        messages: [{ role: 'user', content: synthesisPrompt }],
      });

      const run = await openai.beta.threads.runs.create(thread.id, {
        assistant_id: alignerAssistant.assistantId,
      });

      // Poll for completion (2.5s interval, max 2 minutes)
      let runStatus = await openai.beta.threads.runs.retrieve(run.id, { thread_id: thread.id });
      let pollCount = 0;
      const maxPolls = 48; // 2 minutes max (48 * 2.5s)
      const POLL_INTERVAL = 2500;

      while (runStatus.status === 'queued' || runStatus.status === 'in_progress') {
        pollCount++;
        
        if (pollCount >= maxPolls) {
          throw new Error('Finalize strategy timeout - Aligner did not respond within 2 minutes');
        }

        await new Promise(resolve => setTimeout(resolve, POLL_INTERVAL));
        runStatus = await openai.beta.threads.runs.retrieve(run.id, { thread_id: thread.id });
      }

      if (runStatus.status !== 'completed') {
        throw new Error(`Aligner assistant run failed with status: ${runStatus.status}`);
      }

      // Get assistant's response
      const messages = await openai.beta.threads.messages.list(thread.id);
      const assistantMessage = messages.data.find(msg => msg.role === 'assistant');
      
      if (!assistantMessage) {
        throw new Error('No response from Aligner assistant');
      }

      const finalizedBrief = assistantMessage.content
        .filter((c: any) => c.type === 'text')
        .map((c: any) => c.text.value)
        .join('').trim();
      
      if (!finalizedBrief) {
        throw new Error('Failed to generate finalized strategy');
      }

      console.log('[E-Hub Finalize] ✅ Campaign Brief synthesized:', finalizedBrief.substring(0, 100) + '...');
      
      // Return the brief without saving (let user edit first)
      res.json({ finalizedStrategy: finalizedBrief });
    } catch (error: any) {
      console.error('Error finalizing strategy:', error);
      res.status(500).json({ message: error.message || 'Failed to finalize strategy' });
    }
  });

