  // Import recipients from Google Sheets (admin only)
  app.post('/api/sequences/:id/recipients', isAuthenticatedCustom, isAdmin, async (req: any, res) => {
    try {
      const { id } = req.params;
      
      // Validate sheetId
      const { sheetId } = z.object({
        sheetId: z.string().min(1, 'Google Sheet ID is required'),
      }).parse(req.body);

      // Check sequence exists
      const sequence = await storage.getSequence(id, req.user.tenantId);
      if (!sequence) {
        return res.status(404).json({ message: 'Sequence not found' });
      }

      // Get Google Sheets data
      const userIntegration = await storage.getUserIntegration(req.user.id);
      if (!userIntegration?.googleAccessToken) {
        return res.status(400).json({ message: 'Google Sheets not connected' });
      }

      // Fetch data from Store Database sheet (extended range to include all relevant columns)
      const rows = await googleSheets.getSheetData(
        userIntegration.googleAccessToken,
        sheetId,
        'Store Database!A:Z' // Extended range to capture all columns
      );

      if (!rows || rows.length === 0) {
        return res.status(400).json({ message: 'No data found in sheet' });
      }

      // Dynamic header lookup (case-insensitive)
      const headers = rows[0].map((h: any) => h?.toString().toLowerCase().trim() || '');
      const nameIndex = headers.findIndex((h: string) => h === 'name');
      const emailIndex = headers.findIndex((h: string) => h === 'email');
      const linkIndex = headers.findIndex((h: string) => h === 'link');
      const hoursIndex = headers.findIndex((h: string) => h === 'hours');
      const salesSummaryIndex = headers.findIndex((h: string) => h === 'sales summary');
      const stateIndex = headers.findIndex((h: string) => h === 'state');

      if (nameIndex === -1 || emailIndex === -1) {
        return res.status(400).json({ message: 'Required columns (Name, Email) not found in sheet' });
      }

      console.log('[E-Hub Import] Header mapping:', {
        name: nameIndex,
        email: emailIndex,
        link: linkIndex,
        hours: hoursIndex,
        salesSummary: salesSummaryIndex,
        state: stateIndex,
      });

      // Email regex for validation
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      
      // Process rows with dynamic column lookup
      const recipients = [];
      const seenEmails = new Set<string>();
      const skippedRows: string[] = [];

      for (const row of rows.slice(1)) { // Skip header row
        const rawName = row[nameIndex]?.toString().trim();
        const rawEmail = row[emailIndex]?.toString().trim();
        const rawLink = linkIndex !== -1 ? row[linkIndex]?.toString().trim() : null;
        const rawHours = hoursIndex !== -1 ? row[hoursIndex]?.toString().trim() : null;
        const rawSalesSummary = salesSummaryIndex !== -1 ? row[salesSummaryIndex]?.toString().trim() : null;
        const rawState = stateIndex !== -1 ? row[stateIndex]?.toString().trim() : null;

        // Skip blank or whitespace-only rows
        if (!rawName || !rawEmail || rawName === '' || rawEmail === '') {
          continue;
        }

        const email = rawEmail.toLowerCase();
        const name = rawName;

        // Validate email format with regex
        if (!emailRegex.test(email)) {
          skippedRows.push(`Invalid email: ${email}`);
          continue;
        }

        // Skip duplicates in current batch
        if (seenEmails.has(email)) continue;

        // Check if recipient already exists in database
        const existing = await storage.findRecipientByEmail(id, email);
        if (existing) continue;

        // Parse business hours and detect timezone
        let timezone = 'America/New_York'; // Default fallback
        let businessHours = rawHours || '';

        if (rawState) {
          // Normalize state string: handle various formats
          // Examples: "CA – California", "CA (California)", "CA/USA", "CA" → "CA"
          let normalizedState = rawState
            .replace(/\([^)]*\)/g, '') // Remove parenthetical content: "CA (California)" → "CA"
            .split(/[-–—\/]/) // Split on dashes and slashes
            .map(s => s.trim()) // Trim whitespace
            .filter(s => s && s.toLowerCase() !== 'usa') // Remove empty and "USA"
            [0] // Take first segment
            .toUpperCase(); // Uppercase for matching
          
          timezone = resolveTimezone(normalizedState);
          console.log(`[E-Hub Import] Resolved timezone for ${email}: "${rawState}" → "${normalizedState}" → ${timezone}`);
        } else {
          console.warn(`[E-Hub Import] No state found for ${email}, using default timezone`);
        }

        // Validate using Zod schema before adding to batch
        try {
          insertSequenceRecipientSchema.parse({
            sequenceId: id,
            email,
            name,
            link: rawLink || '',
            salesSummary: rawSalesSummary || '',
            businessHours,
            state: rawState || null,
            timezone,
            status: 'pending',
          });

          seenEmails.add(email);
          recipients.push({
            sequenceId: id,
            email,
            name,
            link: rawLink || '',
            salesSummary: rawSalesSummary || '',
            businessHours,
            state: rawState || null,
            timezone,
            status: 'pending',
          });
        } catch (validationError) {
          skippedRows.push(`Validation failed for ${email}: ${name}`);
          continue;
        }
      }

      if (recipients.length === 0) {
        return res.json({ 
          message: 'No new recipients to import', 
          count: 0,
          skipped: skippedRows.length,
          skippedReasons: skippedRows.slice(0, 10) // Show first 10 reasons
        });
      }

      // MATRIX2: Just create recipients with metadata - Matrix2 slot assigner handles scheduling
      const stepDelays = (sequence.stepDelays || []).map((d: string | number) => parseFloat(String(d)));
      
      if (stepDelays.length === 0) {
        return res.status(400).json({ message: 'Sequence has no steps configured' });
      }

      // Bulk insert recipients with metadata
      const created = await storage.addRecipients(recipients);

      // MATRIX2: Mark recipients as in_sequence with currentStep=0
      // The slot assigner will automatically assign them to slots based on their metadata
      for (const recipient of created) {
        await storage.updateRecipientStatus(recipient.id, {
          status: 'in_sequence',
          currentStep: 0,
          nextSendAt: null, // Matrix2 will set this when assigning to slot
        });
      }

      // Update sequence total count
      await storage.updateSequenceStats(id, req.user.tenantId, {
        totalRecipients: (sequence.totalRecipients || 0) + created.length,
      });

      // Invalidate All Contacts cache to reflect new recipients
      const { invalidateCache } = await import('./services/ehubContactsService');
      invalidateCache();

      res.json({ 
        message: 'Recipients imported successfully', 
        count: created.length,
        skipped: skippedRows.length,
        skippedReasons: skippedRows.slice(0, 10) // Show first 10 reasons if any
      });
    } catch (error: any) {
      if (error.name === 'ZodError') {
        return res.status(400).json({ message: 'Invalid request data', errors: error.errors });
      }
      console.error('Error importing recipients:', error);
      res.status(500).json({ message: error.message || 'Failed to import recipients' });
    }
  });

  // Add contacts to sequence from All Contacts tab (admin only)
  // CLONE of Google Sheets import endpoint with contact data source
  app.post('/api/sequences/:id/contacts', isAuthenticatedCustom, isAdmin, async (req: any, res) => {
    try {
      const { id } = req.params;
      const { contacts, selectAll, search, statusFilter } = req.body;

      // Check sequence exists and get tenantId/projectId from it
      const sequence = await storage.getSequence(id, req.user.tenantId);
      if (!sequence) {
        return res.status(404).json({ message: 'Sequence not found' });
      }
      
      // Get tenantId and projectId from the sequence for proper multi-tenant/project support
      const tenantId = req.user.tenantId;
      const projectId = sequence.projectId;

      // Get contacts data - either from provided array or via getAllContacts
      let contactsToAdd: any[] = [];

      if (selectAll) {
        // Fetch all contacts matching filter
        const { getAllContacts } = await import('./services/ehubContactsService');
        const { contacts: allContacts } = await getAllContacts({
          page: 1,
          pageSize: 99999, // Get all
          search: search || '',
          statusFilter: statusFilter || 'all',
          tenantId,
          projectId,
        });
        contactsToAdd = allContacts;
      } else {
        // Use provided contacts array
        contactsToAdd = contacts || [];
      }

      if (contactsToAdd.length === 0) {
        return res.json({ message: 'No contacts to add', count: 0 });
      }

      // ENRICH CONTACTS: Build a lookup map from Store Database to populate missing link fields
      const storeEmailToLink = new Map<string, { link?: string; salesSummary?: string }>();
      const storeSheet = await storage.getGoogleSheetByPurpose('Store Database', (req.user as any).tenantId);
      
      if (storeSheet) {
        const storeData = await googleSheets.readSheetData(
          storeSheet.spreadsheetId,
          `${storeSheet.sheetName}!A:ZZ`
        );
        
        if (storeData && storeData.length > 0) {
          const headers = storeData[0].map((h: string) => h.toLowerCase().trim());
          const emailIndex = headers.indexOf('email');
          const linkIndex = headers.indexOf('link');
          const salesSummaryIndex = headers.indexOf('sales-ready summary');
          
          if (emailIndex !== -1) {
            for (let i = 1; i < storeData.length; i++) {
              const row = storeData[i];
              const rowEmail = row[emailIndex]?.toString().toLowerCase().trim();
              if (rowEmail && rowEmail.includes('@')) {
                storeEmailToLink.set(rowEmail, {
                  link: linkIndex !== -1 ? row[linkIndex] : undefined,
                  salesSummary: salesSummaryIndex !== -1 ? row[salesSummaryIndex] : undefined
                });
              }
            }
          }
        }
      }

      // Email regex for validation
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      
      // Process contacts with same validation as Google Sheets import
      const recipients = [];
      const seenEmails = new Set<string>();
      const skippedRows: string[] = [];

      for (const contact of contactsToAdd) {
        const rawEmail = contact.email?.toString().trim();
        const rawName = contact.name?.toString().trim();

        // Skip blank or whitespace-only contacts
        if (!rawName || !rawEmail || rawName === '' || rawEmail === '') {
          continue;
        }

        const email = rawEmail.toLowerCase();
        const name = rawName;

        // Validate email format with regex
        if (!emailRegex.test(email)) {
          skippedRows.push(`Invalid email: ${email}`);
          continue;
        }

        // Skip duplicates in current batch
        if (seenEmails.has(email)) continue;

        // Check if recipient already exists in database
        const existing = await storage.findRecipientByEmail(id, email);
        if (existing) continue;

        // ENRICH: Look up email in Store Database to get link and salesSummary
        const storeData = storeEmailToLink.get(email);
        const enrichedLink = contact.link || storeData?.link || '';
        const enrichedSalesSummary = contact.salesSummary || storeData?.salesSummary || '';

        // Use contact's data directly (already has timezone/businessHours from source)
        const businessHours = contact.hours || contact.businessHours || '';
        const timezone = contact.timezone || 'America/New_York';
        const state = contact.state || null;

        // Validate using Zod schema before adding to batch
        try {
          insertSequenceRecipientSchema.parse({
            tenantId,
            sequenceId: id,
            email,
            name,
            link: enrichedLink,
            salesSummary: enrichedSalesSummary,
            businessHours,
            state,
            timezone,
            status: 'pending',
          });

          seenEmails.add(email);
          recipients.push({
            tenantId,
            sequenceId: id,
            email,
            name,
            link: enrichedLink,
            salesSummary: enrichedSalesSummary,
            businessHours,
            state,
            timezone,
            status: 'pending',
          });
        } catch (validationError: any) {
          const errorMsg = validationError?.errors?.[0]?.message || 'Unknown validation error';
          skippedRows.push(`Validation failed for ${email}: ${errorMsg}`);
          continue;
        }
      }

      if (recipients.length === 0) {
        return res.json({ message: 'No new recipients to import', count: 0 });
      }

      // MATRIX2: Just create recipients with metadata - Matrix2 slot assigner handles scheduling
      const stepDelays = (sequence.stepDelays || []).map((d: string | number) => parseFloat(String(d)));
      
      if (stepDelays.length === 0) {
        return res.status(400).json({ message: 'Sequence has no steps configured' });
      }

      // Bulk insert recipients with metadata
      const created = await storage.addRecipients(recipients);

      // MATRIX2: Mark recipients as in_sequence with currentStep=0
      // The slot assigner will automatically assign them to slots based on their metadata
      for (const recipient of created) {
        await storage.updateRecipientStatus(recipient.id, {
          status: 'in_sequence',
          currentStep: 0,
          nextSendAt: null, // Matrix2 will set this when assigning to slot
        });
      }

      // Update sequence total count
      await storage.updateSequenceStats(id, req.user.tenantId, {
        totalRecipients: (sequence.totalRecipients || 0) + created.length,
      });

      // Invalidate All Contacts cache to reflect new recipients
      const { invalidateCache } = await import('./services/ehubContactsService');
      invalidateCache();

      res.json({ message: 'Recipients imported successfully', count: created.length });
    } catch (error: any) {
      if (error.name === 'ZodError') {
        return res.status(400).json({ message: 'Invalid request data', errors: error.errors });
      }
      console.error('Error importing recipients:', error);
      res.status(500).json({ message: error.message || 'Failed to import recipients' });
    }
  });

  // Get recipients for a sequence (admin only)
  // Enriches each recipient with contactedStatus from Commission Tracker
  app.get('/api/sequences/:id/recipients', isAuthenticatedCustom, isAdmin, async (req: any, res) => {
    try {
      const { id } = req.params;
      const { contactedStatus, limit } = req.query; // Renamed from 'status' to 'contactedStatus'

      // Fetch ALL recipients first (no DB filtering)
      const recipients = await storage.getRecipients(id, {});

      // Find Commission Tracker sheet
      const sheets = await storage.getAllActiveGoogleSheets((req.user as any).tenantId);
      const trackerSheet = sheets.find(s => s.sheetPurpose === 'commissions');

      if (!trackerSheet) {
        // Tracker sheet is required for E-Hub to function - return error
        console.error('[E-Hub Recipients] No Commission Tracker found');
        return res.status(503).json({ 
          message: 'Commission Tracker sheet not configured. Please set up the tracker sheet before using E-Hub.' 
        });
      }

      const { spreadsheetId, sheetName } = trackerSheet;

      // Read Commission Tracker sheet
      const range = `${sheetName}!A:ZZ`;
      const rows = await googleSheets.readSheetData(spreadsheetId, range);

      if (rows.length === 0) {
        console.error('[E-Hub Recipients] Commission Tracker sheet is empty');
        return res.status(503).json({ 
          message: 'Commission Tracker sheet is empty. Please ensure headers are configured.' 
        });
      }

      const headers = rows[0];
      const linkIndex = headers.findIndex(h => h?.toString().toLowerCase() === 'link');
      const statusIndex = headers.findIndex(h => h?.toString().toLowerCase() === 'status');
      const pocIndex = headers.findIndex(h => h?.toString().toLowerCase() === 'point of contact');
      const pocEmailIndex = headers.findIndex(h => h?.toString().toLowerCase() === 'poc email');
      const salesSummaryIndex = headers.findIndex(h => h?.toString().toLowerCase() === 'sales-ready summary');

      if (linkIndex === -1) {
        console.error('[E-Hub Recipients] Link column not found in Commission Tracker');
        return res.status(503).json({ 
          message: 'Link column not found in Commission Tracker. Please ensure the sheet has a "Link" column.' 
        });
      }

      // Build TWO maps: one for link matching, one for email matching
      type TrackerData = {
        status: string;
        name: string | null;
        link: string | null;
        salesSummary: string | null;
      };

      const linkDataMap = new Map<string, TrackerData>();
      const emailDataMap = new Map<string, TrackerData>();
      
      for (let i = 1; i < rows.length; i++) {
        const rowLink = rows[i][linkIndex];
        const rowEmail = pocEmailIndex !== -1 ? rows[i][pocEmailIndex] : null;
        const trackerData: TrackerData = {
          status: statusIndex !== -1 ? (rows[i][statusIndex]?.toString().trim() || '') : '',
          name: pocIndex !== -1 ? (rows[i][pocIndex]?.toString().trim() || null) : null,
          link: rowLink ? rowLink.toString().trim() : null,
          salesSummary: salesSummaryIndex !== -1 ? (rows[i][salesSummaryIndex]?.toString().trim() || null) : null,
        };

        // Index by link
        if (rowLink) {
          const normalizedLink = normalizeLink(rowLink.toString().trim());
          linkDataMap.set(normalizedLink, trackerData);
        }

        // Index by email
        if (rowEmail) {
          const normalizedEmail = rowEmail.toString().trim().toLowerCase();
          emailDataMap.set(normalizedEmail, trackerData);
        }
      }

      // Enrich recipients with FRESH data from Commission Tracker
      // Match by Link OR Email
      const enrichedRecipients = recipients.map(recipient => {
        let trackerData: TrackerData | undefined;

        // Try to match by link first
        if (recipient.link) {
          const normalizedRecipientLink = normalizeLink(recipient.link.trim());
          trackerData = linkDataMap.get(normalizedRecipientLink);
        }

        // If no link match, try email match
        if (!trackerData && recipient.email) {
          const normalizedEmail = recipient.email.trim().toLowerCase();
          trackerData = emailDataMap.get(normalizedEmail);
        }

        // Determine contactedStatus with priority:
        // 1. sequence_recipients status (most authoritative) 
        // 2. Fall back to Commission Tracker status if in_progress/pending
        let contactedStatus: 'contacted' | 'not contacted' | 'unknown';
        
        // Check sequence_recipients status first (highest priority)
        const recipientStatus = recipient.status?.toLowerCase() || '';
        if (recipientStatus === 'replied') {
          contactedStatus = 'replied';
        } else if (recipientStatus === 'bounced') {
          contactedStatus = 'bounced';
        } else if (recipientStatus === 'in_sequence') {
          contactedStatus = 'in_sequence';
        } else if (!trackerData) {
          // No tracker row and not in an active sequence status
          contactedStatus = 'unknown';
        } else if (trackerData.status.trim().toLowerCase() === 'contacted') {
          // Commission Tracker shows 'Contacted'
          contactedStatus = 'contacted';
        } else {
          // Tracker row exists but status is not 'Contacted'
          contactedStatus = 'not contacted';
        }

        // Return recipient with FRESH data from Commission Tracker
        // This overrides stale data from import with current sheet data
        return { 
          ...recipient,
          // Override name, link, and salesSummary with fresh tracker data if available
          name: trackerData?.name || recipient.name,
          link: trackerData?.link || recipient.link,
          salesSummary: trackerData?.salesSummary || recipient.salesSummary,
          // Add status fields
          contactedStatus,
          trackerStatus: trackerData?.status || null
        };
      });

      // Filter by contactedStatus if requested (after enrichment)
      let filtered = enrichedRecipients;
      if (contactedStatus) {
        filtered = enrichedRecipients.filter(r => 
          r.contactedStatus.toLowerCase() === contactedStatus.toString().toLowerCase()
        );
      }

      // Apply limit if requested (after filtering)
      if (limit) {
        const limitNum = parseInt(limit.toString());
        filtered = filtered.slice(0, limitNum);
      }

      res.json(filtered);
    } catch (error: any) {
      console.error('Error getting recipients:', error);
      res.status(500).json({ message: error.message || 'Failed to get recipients' });
    }
  });

